code.C:
#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const double inv18 = 1.0/18.0;
    while(T--){
        int N; scanf("%d", &N);
        double ans = 0.5 * N - inv18 + pow(10.0, -N) * inv18;
        printf("%.6f\n", ans);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    const double inv18 = 1.0/18.0;
    while(T--){
        long long N; cin>>N;
        double ans = 0.5 * N - inv18 + pow(10.0, - (double)N) * inv18;
        cout.setf(ios::fixed);
        cout<<setprecision(6)<<ans<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        final double inv18 = 1.0/18.0;
        for(int t=0; t<T; ++t){
            int N = Integer.parseInt(br.readLine().trim());
            double ans = 0.5 * N - inv18 + Math.pow(10.0, -N) * inv18;
            sb.append(String.format(Locale.US, "%.6f", ans)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

